// Get input JSON
const input = $input.first().json;

// Function to recursively find the first array of numbers
function findNumberArray(obj) {
    if (Array.isArray(obj)) {
        if (obj.every(item => typeof item === 'number')) {
            return obj;
        }

        for (const item of obj) {
            const result = findNumberArray(item);
            if (result) return result;
        }
    }

    if (typeof obj === 'object' && obj !== null) {
        for (const key in obj) {
            const result = findNumberArray(obj[key]);
            if (result) return result;
        }
    }

    return null;
}

// Find weather values
const values = findNumberArray(input);

if (!values) {
    throw new Error(
        "Could not find an array of numbers in the incoming JSON."
    );
}

// Calculate statistics
const min = Math.min(...values);
const max = Math.max(...values);
const avg = values.reduce((sum, val) => sum + val, 0) / values.length;

// Generate weather message
let weatherMessage = "";

if (avg < 0.22) {
    weatherMessage =
        "Colombo is expected to experience relatively cool and stable weather conditions today, with only minor variations throughout the forecast period.";
} else if (avg < 0.24) {
    weatherMessage =
        "The weather in Colombo is expected to remain warm and pleasant throughout the day. Forecast values indicate stable atmospheric conditions with minimal fluctuations.";
} else {
    weatherMessage =
        "Colombo is likely to experience warmer conditions today. Residents should expect a hot and humid day and are advised to stay hydrated.";
}

// Append statistics
weatherMessage += ` Forecast statistics: minimum value = ${min.toFixed(
    3
)}, maximum value = ${max.toFixed(
    3
)}, and average value = ${avg.toFixed(3)}.`;

// Return output
return [
    {
        json: {
            weather_message: weatherMessage,
            statistics: {
                minimum: min,
                maximum: max,
                average: avg,
                total_predictions: values.length
            }
        }
    }
];
